171	// In most cases you should not use this function directly, but the Test or TestRunning function.
172	func NewIntegrationTestBuilder(conf IntegrationTestConfig) *IntegrationTestBuilder {
173		// Code fences.
174		conf.TxtarString = strings.ReplaceAll(conf.TxtarString, "§§§", "```")
175		// Multiline strings.
176		conf.TxtarString = strings.ReplaceAll(conf.TxtarString, "§§", "`")
177	
178		data := txtar.Parse([]byte(conf.TxtarString))
179	
180		if conf.NFDFormOnDarwin {
181			for i, f := range data.Files {
182				data.Files[i].Name = norm.NFD.String(f.Name)
183			}
184		}
185	
186		c, ok := conf.T.(*qt.C)
187		if !ok {
188			c = qt.New(conf.T)
189		}
190	
191		if conf.NeedsOsFS {
192			if !filepath.IsAbs(conf.WorkingDir) {
193				tempDir, clean, err := htesting.CreateTempDir(hugofs.Os, "hugo-integration-test")
194				c.Assert(err, qt.IsNil)
195				conf.WorkingDir = filepath.Join(tempDir, conf.WorkingDir)
196				if !conf.PrintAndKeepTempDir {
197					c.Cleanup(clean)
198				} else {
199					fmt.Println("\nUsing WorkingDir dir:", conf.WorkingDir)
200				}
201			}
202		} else if conf.WorkingDir == "" {
203			conf.WorkingDir = helpers.FilePathSeparator
204		}
205	
206		return &IntegrationTestBuilder{
207			Cfg:  conf,
208			C:    c,
209			data: data,
210		}
211	}
