254	func (s *IntegrationTestPageHelper) siteIntsToMap(matrix, complements sitesmatrix.VectorStore) map[string]map[string][]string {
255		dconf := s.p.s.Conf.ConfiguredDimensions()
256		intSetsToMap := func(intSets sitesmatrix.VectorStore) map[string][]string {
257			var languages, versions, roles []string
258	
259			keys1, keys2, keys3 := intSets.KeysSorted()
260	
261			for _, v := range keys1 {
262				languages = append(languages, dconf.ConfiguredLanguages.ResolveName(v))
263			}
264			for _, v := range keys2 {
265				versions = append(versions, dconf.ConfiguredVersions.ResolveName(v))
266			}
267			for _, v := range keys3 {
268				roles = append(roles, dconf.ConfiguredRoles.ResolveName(v))
269			}
270	
271			return map[string][]string{
272				"languages": languages,
273				"versions":  versions,
274				"roles":     roles,
275			}
276		}
277	
278		return map[string]map[string][]string{
279			"matrix":      intSetsToMap(matrix),
280			"complements": intSetsToMap(complements),
281		}
282	}
