369	// AssertLogContains asserts that the last build log contains the given strings.
370	// Each string can be negated with a hglob.NegationPrefix prefix.
371	func (s *IntegrationTestBuilder) AssertLogContains(els ...string) {
372		s.Helper()
373		for _, el := range els {
374			var negate bool
375			el, negate = s.negate(el)
376			check := qt.Contains
377			if negate {
378				check = qt.Not(qt.Contains)
379			}
380			s.Assert(s.lastBuildLog, check, el)
381		}
382	}
