384	// AssertLogMatches asserts that the last build log matches the given regular expressions.
385	// The regular expressions can be negated with a hglob.NegationPrefix prefix.
386	func (s *IntegrationTestBuilder) AssertLogMatches(expression string) {
387		s.Helper()
388		var negate bool
389		expression, negate = s.negate(expression)
390		re := regexp.MustCompile(expression)
391		checker := qt.IsTrue
392		if negate {
393			checker = qt.IsFalse
394		}
395	
396		s.Assert(re.MatchString(s.lastBuildLog), checker, qt.Commentf(s.lastBuildLog))
397	}
