416	func (s *IntegrationTestBuilder) negate(match string) (string, bool) {
417		var negate bool
418		if strings.HasPrefix(match, hglob.NegationPrefix) {
419			negate = true
420			match = strings.TrimPrefix(match, hglob.NegationPrefix)
421		}
422		return match, negate
423	}
