425	func (s *IntegrationTestBuilder) AssertFileContent(filename string, matches ...string) {
426		s.Helper()
427		content := strings.TrimSpace(s.FileContent(filename))
428	
429		for _, m := range matches {
430			cm := qt.Commentf("File: %s Expect:\n%s Got:\n%s\nWith Space Visuals:\n%s", filename, m, content, util.VisualizeSpaces([]byte(content)))
431			lines := strings.SplitSeq(m, "\n")
432			for match := range lines {
433				match = strings.TrimSpace(match)
434				if match == "" || strings.HasPrefix(match, "#") {
435					continue
436				}
437				var negate bool
438				match, negate = s.negate(match)
439				if negate {
440					s.Assert(content, qt.Not(qt.Contains), match, cm)
441					continue
442				}
443				s.Assert(content, qt.Contains, match, cm)
444			}
445		}
446	}
