534	func (s *IntegrationTestBuilder) AssertFs(fs afero.Fs, matches ...string) {
535		s.Helper()
536		var buff bytes.Buffer
537		s.Assert(s.printAndCheckFs(fs, "", &buff), qt.IsNil)
538		printFsLines := strings.Split(buff.String(), "\n")
539		sort.Strings(printFsLines)
540		content := strings.TrimSpace((strings.Join(printFsLines, "\n")))
541		for _, m := range matches {
542			cm := qt.Commentf("Match: %q\nIn:\n%s", m, content)
543			lines := strings.SplitSeq(m, "\n")
544			for match := range lines {
545				match = strings.TrimSpace(match)
546				var negate bool
547				if strings.HasPrefix(match, hglob.NegationPrefix) {
548					negate = true
549					match = strings.TrimPrefix(match, hglob.NegationPrefix)
550				}
551				if negate {
552					s.Assert(content, qt.Not(qt.Contains), match, cm)
553					continue
554				}
555				s.Assert(content, qt.Contains, match, cm)
556			}
557		}
558	}
