560	func (s *IntegrationTestBuilder) printAndCheckFs(fs afero.Fs, path string, w io.Writer) error {
561		if fs == nil {
562			return nil
563		}
564	
565		return afero.Walk(fs, path, func(path string, info os.FileInfo, err error) error {
566			if err != nil {
567				return fmt.Errorf("error: path %q: %s", path, err)
568			}
569			path = filepath.ToSlash(path)
570			if path == "" {
571				path = "."
572			}
573			var size int64
574			if !info.IsDir() {
575				size = info.Size()
576				f, err := fs.Open(path)
577				if err != nil {
578					return fmt.Errorf("error: path %q: %s", path, err)
579				}
580				defer f.Close()
581				// This will panic if the file is a directory.
582				var buf [1]byte
583				io.ReadFull(f, buf[:])
584			}
585			fmt.Fprintf(w, "%06d %s %t\n", size, path, info.IsDir())
586			return nil
587		})
588	}
