620	func (s *IntegrationTestBuilder) Build() *IntegrationTestBuilder {
621		s.Helper()
622		_, err := s.BuildE()
623	
624		if err != nil && strings.Contains(err.Error(), "error(s)") {
625			err = fmt.Errorf("%w: %s", err, s.lastBuildLog)
626		}
627	
628		if s.Cfg.Verbose || err != nil {
629			if s.H != nil && err == nil {
630				for s := range s.H.allSites(nil) {
631					m := s.pageMap
632					var buff bytes.Buffer
633					fmt.Fprintf(&buff, "======= PageMap for site %q  =======\n\n", s.resolveDimensionNames())
634					m.debugPrint("", 999, &buff)
635					fmt.Println(buff.String())
636				}
637			}
638		} else if s.Cfg.LogLevel <= logg.LevelDebug {
639			fmt.Println(s.lastBuildLog)
640		}
641		s.Assert(err, qt.IsNil)
642		if s.Cfg.RunGC {
643			s.GCCount, err = s.H.GC()
644			s.Assert(err, qt.IsNil)
645		}
646	
647		s.Cleanup(func() {
648			if h := s.H; h != nil {
649				s.Assert(h.Close(), qt.IsNil)
