825	func (s *IntegrationTestBuilder) initBuilder() error {
826		var initErr error
827		s.builderInit.Do(func() {
828			var afs afero.Fs
829			if s.Cfg.NeedsOsFS {
830				afs = afero.NewOsFs()
831			} else {
832				afs = afero.NewMemMapFs()
833			}
834	
835			if s.Cfg.LogLevel == 0 {
836				s.Cfg.LogLevel = logg.LevelError
837			}
838	
839			isBinaryRe := regexp.MustCompile(`^(.*)(\.png|\.jpg)$`)
840	
841			const dataSourceFilenamePrefix = "sourcefilename:"
842	
843			for _, f := range s.data.Files {
844				filename := filepath.Join(s.Cfg.WorkingDir, f.Name)
845				data := bytes.TrimSuffix(f.Data, []byte("\n"))
846				datastr := strings.TrimSpace(string(data))
847				if strings.HasPrefix(datastr, dataSourceFilenamePrefix) {
848					// Read from file relative to the current dir.
849					var err error
850					wd, _ := os.Getwd()
851					filename := filepath.Join(wd, strings.TrimSpace(strings.TrimPrefix(datastr, dataSourceFilenamePrefix)))
852					data, err = os.ReadFile(filename)
853					s.Assert(err, qt.IsNil)
854				} else if isBinaryRe.MatchString(filename) {
855					var err error
856					data, err = base64.StdEncoding.DecodeString(string(data))
857					s.Assert(err, qt.IsNil)
858	
859				}
860				s.Assert(afs.MkdirAll(filepath.Dir(filename), 0o777), qt.IsNil)
861				s.Assert(afero.WriteFile(afs, filename, data, 0o666), qt.IsNil)
862			}
863	
864			configDir := "config"
865			if _, err := afs.Stat(filepath.Join(s.Cfg.WorkingDir, "config")); err != nil {
866				configDir = ""
867			}
868	
869			var flags config.Provider
870			if s.Cfg.BaseCfg != nil {
871				flags = s.Cfg.BaseCfg
872			} else {
873				flags = config.New()
874			}
875	
876			if s.Cfg.Running {
877				flags.Set("internal", hmaps.Params{
878					"running": s.Cfg.Running,
879					"watch":   s.Cfg.Running,
880				})
881			} else if s.Cfg.Watching {
882				flags.Set("internal", hmaps.Params{
883					"watch": s.Cfg.Watching,
884				})
885			}
886	
887			if s.Cfg.WorkingDir != "" {
888				flags.Set("workingDir", s.Cfg.WorkingDir)
889			}
890	
891			var w io.Writer
892			if s.Cfg.Verbose || s.Cfg.LogLevel == logg.LevelTrace {
893				w = io.MultiWriter(os.Stdout, &s.logBuff)
894			} else {
895				w = &s.logBuff
896			}
897	
898			var logHookLast func(e *logg.Entry) error
899			if s.Cfg.PanicOnWarning {
900				logHookLast = loggers.PanicOnWarningHook
901			}
902	
903			logger := loggers.New(
904				loggers.Options{
905					StdOut:        w,
906					StdErr:        w,
907					Level:         s.Cfg.LogLevel,
908					DistinctLevel: logg.LevelWarn,
909					HandlerPost:   logHookLast,
910				},
911			)
912	
913			res, err := allconfig.LoadConfig(
914				allconfig.ConfigSourceDescriptor{
915					Flags:     flags,
916					ConfigDir: configDir,
917					Fs:        afs,
918					Logger:    logger,
919					Environ:   s.Cfg.Environ,
920				},
921			)
922			if err != nil {
923				initErr = err
924				return
925			}
926	
927			fs := hugofs.NewFrom(afs, res.LoadingInfo.BaseConfig)
928	
929			s.Assert(err, qt.IsNil)
930	
931			// changes received from Hugo in watch mode.
932			// In the full setup, this channel is created in the commands package.
933			changesFromBuild := make(chan []identity.Identity, 10)
934	
935			depsCfg := deps.DepsCfg{Configs: res, Fs: fs, LogLevel: logger.Level(), StdErr: logger.StdErr(), ChangesFromBuild: changesFromBuild, IsIntegrationTest: true}
936			sites, err := NewHugoSites(depsCfg)
937			if err != nil {
938				initErr = err
939				return
940			}
941			if sites == nil {
942				initErr = errors.New("no sites")
943				return
944			}
945	
946			go func() {
947				for id := range changesFromBuild {
948					whatChanged := &WhatChanged{}
949					for _, v := range id {
950						whatChanged.Add(v)
951					}
952					bcfg := s.Cfg.BuildCfg
953					bcfg.WhatChanged = whatChanged
954					if err := s.build(bcfg); err != nil {
955						s.Fatalf("Build failed after change: %s", err)
956					}
957				}
958			}()
959	
960			s.H = sites
961			s.fs = fs
962	
963			if s.Cfg.NeedsNpmInstall {
964				wd, _ := os.Getwd()
965				s.Assert(os.Chdir(s.Cfg.WorkingDir), qt.IsNil)
966				s.C.Cleanup(func() { os.Chdir(wd) })
967				sc := security.DefaultConfig
968				sc.Exec.Allow, err = security.NewWhitelist("npm")
969				s.Assert(err, qt.IsNil)
970				ex := hexec.New(sc, s.Cfg.WorkingDir, loggers.NewDefault())
971				command, err := ex.New("npm", "install")
972				s.Assert(err, qt.IsNil)
973				s.Assert(command.Run(), qt.IsNil)
974	
975			}
976		})
977	
978		return initErr
979	}
