1021	// We simulate the fsnotify events.
1022	// See the test output in https://github.com/bep/fsnotifyeventlister for what events gets produced
1023	// by the different OSes.
1024	func (s *IntegrationTestBuilder) changeEvents() []fsnotify.Event {
1025		var (
1026			events    []fsnotify.Event
1027			isLinux   = runtime.GOOS == "linux"
1028			isMacOs   = runtime.GOOS == "darwin"
1029			isWindows = runtime.GOOS == "windows"
1030		)
1031	
1032		for _, v := range s.removedFiles {
1033			events = append(events, fsnotify.Event{
1034				Name: v,
1035				Op:   fsnotify.Remove,
1036			})
1037		}
1038		for _, v := range s.renamedFiles {
1039			events = append(events, fsnotify.Event{
1040				Name: v,
1041				Op:   fsnotify.Rename,
1042			})
1043		}
1044	
1045		for _, v := range s.renamedDirs {
1046			events = append(events, fsnotify.Event{
1047				Name: v,
1048				// This is what we get on MacOS.
1049				Op: fsnotify.Remove | fsnotify.Rename,
1050			})
1051		}
1052	
1053		for _, v := range s.changedFiles {
1054			events = append(events, fsnotify.Event{
1055				Name: v,
1056				Op:   fsnotify.Write,
1057			})
1058			if isLinux || isWindows {
1059				// Duplicate write events, for some reason.
1060				events = append(events, fsnotify.Event{
1061					Name: v,
1062					Op:   fsnotify.Write,
1063				})
1064			}
1065			if isMacOs {
1066				events = append(events, fsnotify.Event{
1067					Name: v,
1068					Op:   fsnotify.Chmod,
1069				})
1070			}
1071		}
1072		for _, v := range s.createdFiles {
1073			events = append(events, fsnotify.Event{
1074				Name: v,
1075				Op:   fsnotify.Create,
1076			})
1077			if isLinux || isWindows {
1078				events = append(events, fsnotify.Event{
1079					Name: v,
1080					Op:   fsnotify.Write,
1081				})
1082			}
1083	
1084		}
1085	
1086		// Shuffle events.
1087		for i := range events {
1088			j := rand.Intn(i + 1)
1089			events[i], events[j] = events[j], events[i]
1090		}
1091	
1092		return events
1093	}
