1107			start := 0
1108			if hadSlash {
1109				start = 1
1110			}
1111			end := start + 1
1112	
1113			parts := strings.Split(filename, helpers.FilePathSeparator)
1114			if parts[start] == "work" {
1115				end++
1116			}
1117	
1118			s.Assert(err, qt.IsNil)
1119	
1120		}
1121		return string(b)
1122	}
